const SEMVER_RE = /v?(0|[1-9]\d*)\.(0|[1-9]\d*)\.(0|[1-9]\d*)(?:-((?:0|[1-9]\d*|\d*[a-zA-Z-][0-9a-zA-Z-]*)(?:\.(?:0|[1-9]\d*|\d*[a-zA-Z-][0-9a-zA-Z-]*))*))?(?:\+([0-9a-zA-Z-]+(?:\.[0-9a-zA-Z-]+)*))?/g;
const found = [];
let m;
while ((m = SEMVER_RE.exec(input)) !== null) {
  found.push({
    raw: m[0],
    major: parseInt(m[1]), minor: parseInt(m[2]), patch: parseInt(m[3]),
    pre: m[4] || null, build: m[5] || null,
  });
  if (found.length >= 2) break;
}
if (found.length === 0) return { output: 'No valid semver found.', outputLanguage: 'text' };

function describe(v) {
  const lines = [
    `Version: ${v.raw}`,
    `  Major:      ${v.major}  (breaking changes)`,
    `  Minor:      ${v.minor}  (new features, backward-compatible)`,
    `  Patch:      ${v.patch}  (bug fixes)`,
  ];
  if (v.pre)   lines.push(`  Pre-release: ${v.pre}`);
  if (v.build) lines.push(`  Build meta:  ${v.build}`);
  lines.push(`  Stable: ${v.pre ? 'No (pre-release)' : 'Yes'}`);
  return lines.join('\n');
}

const out = found.map(describe);

if (found.length === 2) {
  const [a, b] = found;
  let cmp = 0;
  for (const k of ['major','minor','patch']) {
    if (a[k] > b[k]) { cmp = 1; break; }
    if (a[k] < b[k]) { cmp = -1; break; }
  }
  const rel = cmp === 0 ? 'equal to' : cmp > 0 ? 'greater than' : 'less than';
  out.push(`\nComparison: ${a.raw} is ${rel} ${b.raw}`);
}

return { output: out.join('\n\n'), outputLanguage: 'text' };
